#!/bin/bash
# Refresh deps/libogg/src/ — Xiph libogg snapshot (BSD-3-Clause).
# We only consume the framing/bitwise C files plus the public headers;
# the upstream autotools / CMake build system is bypassed in favour of
# a hand-written CMake fragment (see cmake/libvorbis.cmake).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
. "$SCRIPT_DIR/../_lib-update.sh"

LIB_NAME=libogg
LIB_REPO=https://github.com/xiph/ogg.git
LIB_TAG=v1.3.5
LIB_FETCH=git

refresh_lib

# Generate the platform-specific config_types.h that upstream normally
# produces via autotools. The 64-bit Apple/Linux defaults below are
# what every modern target uses; if a Windows build needs different
# typedefs, ship a deps/patches/libogg/00-config-types.patch.
src="$SCRIPT_DIR/src"
cfg="$src/include/ogg/config_types.h"
if [ ! -f "$cfg" ]; then
    mkdir -p "$(dirname "$cfg")"
    cat > "$cfg" <<'CFG'
/* config_types.h — generated by deps/libogg/update.sh */
#ifndef __CONFIG_TYPES_H__
#define __CONFIG_TYPES_H__
#include <stdint.h>
typedef int16_t  ogg_int16_t;
typedef uint16_t ogg_uint16_t;
typedef int32_t  ogg_int32_t;
typedef uint32_t ogg_uint32_t;
typedef int64_t  ogg_int64_t;
typedef uint64_t ogg_uint64_t;
#endif
CFG
fi
